class Solution(object):
    def reverseWords(self, s):
        vowels = set('aeiou')
        def count_vowels(w):
            return sum(1 for c in w if c in vowels)
        words = s.split()
        target = count_vowels(words[0])
        result = [words[0]]
        for w in words[1:]:
            result.append(w[::-1] if count_vowels(w) == target else w)
        return ' '.join(result)
